// --- CONFIGURAZIONE ---
float zoom = 1.0; 

// Costanti C++ fedeli
float s = 512.0;                 
vec2 center = vec2(-0.748, 0.1); 

// Zoom (Logica esatta C++)
float baseScale = 0.005;
float scale = baseScale / (1.0 + zoom * 20.0);
int maxIter = 200 + int(zoom * 100.0);

// --- LOGICA PRINCIPALE (Mandelbrot) ---
vec2 c = center + (vec2(u, v) - 0.5) * s * scale;
vec2 z = vec2(0.0);
int iter = 0;
float minDist = 100.0; // Orbit Trap

for (int i = 0; i < 2000; i++) {
    if (i >= maxIter) break;
    if (dot(z, z) > 4.0) break;

    // Z = Z^2 + C
    float x = (z.x * z.x - z.y * z.y) + c.x;
    float y = (2.0 * z.x * z.y) + c.y;
    z = vec2(x, y);

    // Trap Distance
    float d = dot(z, z);
    if (d < minDist) minDist = d;
    iter++;
}

// --- COLORAZIONE ---
float t_input = 0.0;   // Il valore 't' passato a getPsychedelicColor
float brightness = 1.0; // Fattore di oscuramento

if (iter >= maxIter) {
    // --- INTERNO: Orbit Trap ---
    // C++: float trap = std::sqrt(minDist) * 10.0f;
    float trap = sqrt(minDist) * 10.0;

    // C++: getPsychedelicColor(trap + 0.5f)
    t_input = trap + 0.5;

    // C++: darker(250) -> Divide luminosità per 2.5 -> Moltiplica per 0.4
    brightness = 0.4;

} else {
    // --- ESTERNO: Smoothing ---
    float dist = dot(z, z);
    if (dist < 0.0001) dist = 0.0001;

    // Smoothing Logaritmico esatto
    float val = sqrt(dist);
    float correction = log(log(val)) / log(2.0);
    float smoothIter = float(iter) + 1.0 - correction;

    // C++: getPsychedelicColor(smoothIter * 0.15f)
    // Qui NON c'è moltiplicazione per 2*PI, l'onda è lenta.
    t_input = smoothIter * 0.15;
    brightness = 1.0;
}

// --- REPLICA ESATTA getPsychedelicColor(float t) ---
// La formula standard Qt/C++ usa fasi fisse su RGB: 0, 2.09, 4.18
vec3 color;

// Nota: NON moltiplico t_input per 6.28. Uso il valore grezzo come in C++.
color.r = 0.5 + 0.5 * sin(t_input + 0.0);
color.g = 0.5 + 0.5 * sin(t_input + 2.094); // + 120 gradi
color.b = 0.5 + 0.5 * sin(t_input + 4.188); // + 240 gradi

return color * brightness;
